record.field:
.query-alert {
    font-family: Helvetica, Arial, sans-serif;
    font-size: 12px;
    color: #24292f;
}

.query-alert__logo-wrap {
    margin: 0 0 16px;
}

.query-alert__logo {
    display: block;
    max-width: 180px;
    max-height: 56px;
    height: auto;
}

.query-alert__meta {
    margin: 0 0 12px;
}

.query-alert__table {
    border-collapse: collapse;
    font-family: inherit;
    font-size: inherit;
}

.query-alert__header {
    text-align: left;
    padding: 5px;
    border: 1px solid #d0d7de;
    background: #f6f8fa;
}

.query-alert__cell {
    padding: 5px;
    border: 1px solid #d0d7de;
    vertical-align: top;
}
